// Validar payload entrante del CRM
const body = $input.first().json.body || {};

const contactId = String(body.contactId || '').trim();
const base64    = String(body.base64 || '').trim();
const fileName  = String(body.fileName || 'file.bin').trim().slice(0, 200);
const mimeType  = String(body.mimeType || 'application/octet-stream').trim().slice(0, 120);
const caption   = String(body.caption || '').trim().slice(0, 1024);
const userName  = String(body.userName || 'Administrador CRM').trim().slice(0, 120);

const validId  = /^[A-Za-z0-9_-]{1,128}$/.test(contactId);
const validB64 = base64.length > 16;
if (!validId || !validB64) {
  return [{ json: { ok: false, status: 400, error: 'Payload inválido', detalle: { validId, validB64 } } }];
}

// Sanitizar nombre de archivo
const safeFileName = fileName.replace(/[^A-Za-z0-9._-]/g, '_');

return [{ json: { ok: true, contactId, base64, fileName: safeFileName, mimeType, caption, userName } }];

// Guardar archivo en VPS (/var/www/media) y construir URL pública
const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const MEDIA_DIR = $env.MEDIA_DIR || '/var/www/media';
const PUBLIC_BASE = ($env.MEDIA_PUBLIC_BASE || 'https://tu-dominio.com/media').replace(/\/$/, '');

if (!fs.existsSync(MEDIA_DIR)) fs.mkdirSync(MEDIA_DIR, { recursive: true });

const ts = Date.now();
const finalName = `${ts}_${item.fileName}`;
const fullPath = path.join(MEDIA_DIR, finalName);

const buf = Buffer.from(item.base64, 'base64');
fs.writeFileSync(fullPath, buf);

const mediaUrl = `${PUBLIC_BASE}/${finalName}`;

return [{ json: {
  contactId: item.contactId,
  mediaUrl,
  mimeType: item.mimeType,
  fileName: finalName,
  caption: item.caption,
  userName: item.userName
} }];
